4	type Settings = {
5	    ClpStorageEngine: string;
6	    ClpQueryEngine: string;
7	    LogsInputType: string;
8	    LogsInputRootDir: string | null;
9	    MaxDatasetsPerQuery: number | null;
10	    MongoDbSearchResultsMetadataCollectionName: string;
11	    SqlDbClpArchivesTableName: string;
12	    SqlDbClpDatasetsTableName: string;
13	    SqlDbClpFilesTableName: string;
14	    SqlDbClpTablePrefix: string;
15	    SqlDbCompressionJobsTableName: string;
16	};
17	
18	/**
19	 * Loads application settings from a `settings.json` file.
20	 *
21	 * This function fetches a JSON file named `settings.json` from the server
22	 * and parses its contents into a `Settings` object.
23	 *
24	 * @return
25	 * @throws {Error} If the fetch or JSON parsing fails, an error is thrown with the original cause.
26	 */
27	const loadSettings = async (): Promise<Settings> => {
28	    try {
29	        const response = await axios.get<Settings>("settings.json");
30	        return response.data;
31	    } catch (e: unknown) {
32	        throw new Error("Failed to fetch settings.", {cause: e});
33	    }
34	};
35	
36	const settings: Settings = await loadSettings();
37	
38	
39	export {settings};
