7	interface DashboardLayoutState {
8	  dashboard: Dashboard | null;
9	  isLoading: boolean;
10	  error: string | null;
11	  isEditing: boolean;
12	  isDirty: boolean;
13	  selectedPanelId: string | null;
14	  activeTabId: string | null;
15	
16	  setDashboard: (dashboard: Dashboard) => void;
17	  updatePanel: (panelId: string, updates: Partial<DashboardPanel>) => void;
18	  updatePanelGridPos: (panelId: string, gridPos: GridPos) => void;
19	  addPanel: (type: PanelType) => void;
20	  removePanel: (panelId: string) => void;
21	  setVariables: (variables: Dashboard["variables"]) => void;
22	  setEditing: (isEditing: boolean) => void;
23	  setSelectedPanelId: (panelId: string | null) => void;
24	  setActiveTabId: (tabId: string | null) => void;
25	  addTab: (title: string) => void;
26	  removeTab: (tabId: string) => void;
27	  reset: () => void;
28	}
29	
30	const DEFAULT_GRID_POS: Record<string, GridPos> = {
31	  timeseries: {x: 0, y: 0, w: 6, h: 4},
32	  stat: {x: 0, y: 0, w: 3, h: 2},
33	  table: {x: 0, y: 0, w: 12, h: 4},
34	  barchart: {x: 0, y: 0, w: 6, h: 4},
35	  logs: {x: 0, y: 0, w: 12, h: 4},
36	  markdown: {x: 0, y: 0, w: 6, h: 2},
37	  gauge: {x: 0, y: 0, w: 3, h: 3},
38	  heatmap: {x: 0, y: 0, w: 6, h: 4},
39	  piechart: {x: 0, y: 0, w: 4, h: 4},
40	};
41	
42	export const useDashboardLayoutStore = create<DashboardLayoutState>()(
43	  temporal(
44	    (set, get) => ({
45	      dashboard: null,
46	      isLoading: false,
47	      error: null,
48	      isEditing: false,
49	      isDirty: false,
50	      selectedPanelId: null,
51	      activeTabId: null,
52	
53	      setDashboard: (dashboard) => set({dashboard, isLoading: false, error: null, isDirty: false, activeTabId: dashboard.tabs?.[0]?.id ?? null}),
54	      updatePanel: (panelId, updates) => {
55	        const d = get().dashboard;
56	        if (!d) return;
57	        set({
58	          dashboard: {
59	            ...d,
60	            panels: d.panels.map((p) => p.id === panelId ? {...p, ...updates} : p),
61	          },
62	          isDirty: true,
63	        });
64	      },
65	      updatePanelGridPos: (panelId, gridPos) => {
66	        const d = get().dashboard;
67	        if (!d) return;
68	        set({
69	          dashboard: {
70	            ...d,
71	            panels: d.panels.map((p) => p.id === panelId ? {...p, gridPos} : p),
72	          },
73	          isDirty: true,
74	        });
75	      },
76	      addPanel: (type) => {
77	        const d = get().dashboard;
78	        if (!d) return;
79	        const maxY = d.panels.reduce((max, p) => Math.max(max, p.gridPos.y + p.gridPos.h), 0);
80	        const id = `panel-${Date.now()}`;
81	        const requiresQuery = false !== getPanelPlugin(type)?.meta.requiresQuery;
82	        const dsType = "logs" === type ? "clp" : "mysql";
83	        const query = "clp" === dsType ?
84	          {queryString: "", datasets: []} :
85	          "";
86	        const newPanel: DashboardPanel = {
87	          id,
88	          type,
89	          title: type.charAt(0).toUpperCase() + type.slice(1),
90	          gridPos: {...DEFAULT_GRID_POS[type] ?? {x: 0, y: 0, w: 6, h: 4}, y: maxY},
91	          datasource: {type: dsType, uid: "default"},
92	          queries: requiresQuery ? [{refId: "A", datasource: {type: dsType, uid: "default"}, query}] : [],
93	          options: {},
94	        };
95	        set({
96	          dashboard: {...d, panels: [...d.panels, newPanel]},
97	          isDirty: true,
98	          selectedPanelId: id,
99	        });
100	      },
101	      removePanel: (panelId) => {
102	        const d = get().dashboard;
103	        if (!d) return;
104	        const remaining = d.panels.filter((p) => p.id !== panelId);
105	        const compacted = autoCompact(remaining);
106	        set({
107	          dashboard: {...d, panels: compacted},
108	          isDirty: true,
109	          selectedPanelId: get().selectedPanelId === panelId ? null : get().selectedPanelId,
110	        });
111	      },
112	      setVariables: (variables) => {
113	        const d = get().dashboard;
114	        if (!d) return;
115	        set({
116	          dashboard: {...d, variables},
117	          isDirty: true,
118	        });
119	      },
120	      setEditing: (isEditing) => set({isEditing}),
121	      setSelectedPanelId: (panelId) => set({selectedPanelId: panelId}),
122	      setActiveTabId: (tabId) => set({activeTabId: tabId}),
123	      addTab: (title) => {
124	        const d = get().dashboard;
125	        if (!d) {
126	            return;
127	        }
128	        const id = `tab-${Date.now()}`;
129	        const tabs = [...(d.tabs ?? []), {id, order: (d.tabs?.length ?? 0) + 1, title}] as DashboardTab[];
130	        set({dashboard: {...d, tabs}, isDirty: true, activeTabId: id});
131	      },
132	      removeTab: (tabId) => {
133	        const d = get().dashboard;
134	        if (!d) {
135	            return;
136	        }
137	        const tabs = (d.tabs ?? []).filter((t) => t.id !== tabId);
138	        const panels = d.panels.filter((p) => p.tabId !== tabId);
139	        const newActiveTabId = get().activeTabId === tabId ?
140	            (tabs[0]?.id ?? null) :
141	            get().activeTabId;
142	        set({dashboard: {...d, panels, tabs}, isDirty: true, activeTabId: newActiveTabId});
143	      },
144	      reset: () => set({dashboard: null, isLoading: false, error: null, isDirty: false, selectedPanelId: null, activeTabId: null}),
145	    }),
146	    {
147	      limit: 50,
148	      partialize: (state) => ({
149	        dashboard: state.dashboard,
150	      }),
151	    }
152	  )
153	);
