1	import {
2	    DependencyList,
3	    useEffect,
4	    useState,
5	} from "react";
6	
7	import {Nullable} from "@webui/common/utility-types";
8	
9	import {MongoSocketCursor} from "./MongoSocketCursor.js";
10	
11	
12	/**
13	 * Custom hook which returns a real-time reactive array of documents from a `MongoSocketCursor`.
14	 *
15	 * @template T The document type returned by the cursor.
16	 * @param query Function which returns a `MongoSocketCursor` instance or null.
17	 * @param dependencies Array of dependencies for the query.
18	 * @return
19	 * - If `query` returns a `MongoSocketCursor` instance, then hook returns null while
20	 * the subscription is pending, and a reactive array of documents when the subscription is ready.
21	 * - If `query` returns null, then the hook also returns null.
22	 */
23	const useCursor = <T = object>(
24	    query: () => Nullable<MongoSocketCursor>,
25	    dependencies: DependencyList = []
26	): Nullable<T[]> => {
27	    const [data, setData] = useState<Nullable<T[]>>(null);
28	
29	    useEffect(() => {
30	        const cursor = query();
31	
32	        if (null === cursor) {
33	            setData(null);
34	
35	            return () => {
36	            };
37	        }
38	
39	        // Flag to ignore updates after unmounting.
40	        let ignore = false;
41	
42	        // Handler to set data updates from the server.
43	        const onDataUpdate = (dataUpdate: object[]) => {
44	            if (false === ignore) {
45	                setData(dataUpdate as T[]);
46	            }
47	        };
48	
49	        const subscribed = cursor.subscribe(onDataUpdate);
50	
51	        subscribed.catch((error: unknown) => {
52	            console.error("Error during subscription:", error);
53	        });
54	
55	        return () => {
56	            ignore = true;
57	
58	            // For a shortly lived cursor (ex. strict mode), the subscription may have not yet
59	            // recieved the queryID from the server, making it impossible to unsubscribe
60	            // immediately (there is no queryID). The subscribed promise allows unsubcription
61	            // to happen when the subscription actually completes.
62	            subscribed
63	                .then(() => {
64	                    // Unsubscribe will not run if the subscription failed since the promise was
65	                    // rejected.
66	                    cursor.unsubscribe();
67	                })
68	                .catch((error: unknown) => {
69	                    console.error("Error during unsubscription:", error);
70	                });
71	        };
72	    // eslint-disable-next-line react-hooks/exhaustive-deps
73	    }, dependencies);
74	
75	    return data;
76	};
77	
78	export {useCursor};
79	

