1	/**
2	 * Unique ID for each active unique query. Multiple clients can subscribe to the same ID if the
3	 * queries are identical. The ID is also used to represent the socket room, and MongoDB
4	 * change stream.
5	 */
6	type QueryId = number;
7	
8	/**
9	 * Error response to event.
10	 */
11	interface Err {
12	    error: string;
13	    queryId?: QueryId;
14	}
15	
16	/**
17	 * Success response to event.
18	 */
19	interface Success<T> {
20	    data: T;
21	}
22	
23	/**
24	 * Event response.
25	 */
26	type Response<T> = Err | Success<T>;
27	
28	
29	/**
30	 * Events that the client can emit to the server.
31	 */
32	type ClientToServerEvents = {
33	    "disconnect": () => void;
34	    "collection::find::subscribe": (
35	        requestArgs: {
36	            collectionName: string;
37	            query: object;
38	            options: object;
39	        },
40	        callback: (res: Response<{queryId: QueryId; initialDocuments: object[]}>) => void) => void;
41	    "collection::find::unsubscribe": (
42	        requestArgs: {
43	            queryId: QueryId;
44	        }
45	    ) => Promise<void>;
46	};
47	
48	/**
49	 * Events that the server can emit to the client.
50	 */
51	interface ServerToClientEvents {
52	    // eslint-disable-next-line no-warning-comments
53	    // TODO: Consider replacing this with `collection::find::update${number}`, which will
54	    // limit callbacks being triggered in the client to their respective query IDs.
55	    "collection::find::update": (respArgs: {
56	        queryId: QueryId;
57	        data: object[];
58	    }) => void;
59	}
60	
61	/**
62	 * Empty but required by Socket IO.
63	 */
64	// eslint-disable-next-line @typescript-eslint/no-empty-object-type
65	interface InterServerEvents {
66	}
67	
68	/**
69	 * Collection associated with each socket connection.
70	 */
71	interface SocketData {
72	    collectionName?: string;
73	}
74	
75	export type {
76	    ClientToServerEvents,
77	    Err,
78	    InterServerEvents,
79	    QueryId,
80	    Response,
81	    ServerToClientEvents,
82	    SocketData,
83	};
