14	type ClpSPayload = Pick<CompressionJobCreation, "dataset" | "timestampKey" | "unstructured">;
15	
16	type S3PathsPayload = Pick<S3CompressionJobCreation, "keyPrefix" | "keys">;
17	
18	type ClpSFormValues = Pick<
19	    S3CompressionJobCreation,
20	    "bufferChannelCapacity" |
21	    "bufferFlushThresholdBytes" |
22	    "bufferTimeoutSec" |
23	    "dataset" |
24	    "scanningIntervalSec" |
25	    "timestampKey" |
26	    "unstructured"
27	>;
