29	
30	/**
31	 * Applies CLP-S fields to a job payload.
32	 *
33	 * @param payload
34	 * @param payload.dataset
35	 * @param payload.timestampKey
36	 * @param payload.unstructured
37	 * @param values
38	 */
39	const applyClpSFields = (
40	    payload: ClpSPayload,
41	    values: ClpSFormValues,
42	) => {
43	    if ("undefined" === typeof values.dataset || 0 === values.dataset.length) {
44	        payload.dataset = CLP_DEFAULT_DATASET_NAME;
45	    } else {
46	        payload.dataset = values.dataset;
47	    }
48	    if (true === values.unstructured) {
49	        payload.unstructured = true;
50	    } else if ("undefined" !== typeof values.timestampKey) {
51	        payload.timestampKey = values.timestampKey;
52	    }
53	};
54	
55	/**
56	 * Parses a list of selected S3 paths into keyPrefix/keys fields.
57	 *
58	 * Selection semantics:
59	 * - If a single prefix (ending with "/") is selected: use `keyPrefix` mode.
60	 * - If the bucket root ("") is selected: use `keyPrefix` with empty string.
61	 * - If only object keys are selected: use `keys` mode.
62	 *
63	 * @param s3Payload
64	 * @param s3Payload.keyPrefix
65	 * @param s3Payload.keys
66	 * @param s3Paths Selected values from the S3 TreeSelect.
67	 */
68	const applyS3Paths = (
69	    s3Payload: S3PathsPayload,
70	    s3Paths: string[],
71	) => {
72	    // Separate prefixes (ending with "/" or empty string for root) from object keys.
73	    const prefixes = s3Paths.filter((p) => p.endsWith("/") || "" === p);
74	    const objectKeys = s3Paths.filter((p) => false === p.endsWith("/") && "" !== p);
75	
76	    if (0 < prefixes.length && 0 === objectKeys.length) {
77	        const [firstPrefix] = prefixes;
78	        s3Payload.keyPrefix = firstPrefix ?? "";
79	    } else if (0 === prefixes.length && 0 < objectKeys.length) {
80	        s3Payload.keys = objectKeys;
81	    } else {
82	        if (0 < prefixes.length) {
83	            s3Payload.keyPrefix = prefixes[0] as string;
84	        }
85	        if (0 < objectKeys.length) {
86	            s3Payload.keys = objectKeys;
87	        }
88	    }
89	};
90	
91	interface BuildS3PayloadArgs {
92	    bucket: string;
93	    regionCode: string;
94	    s3Paths: string[];
95	    scanner: boolean;
96	    values: ClpSFormValues;
97	}
98	
99	/**
100	 * Builds an S3 job payload from form values.
101	 *
102	 * @param args
103	 * @param args.bucket
104	 * @param args.regionCode
105	 * @param args.scanner Whether this is a scanner job.
106	 * @param args.s3Paths
107	 * @param args.values
108	 * @return
109	 */
110	const buildS3Payload = (args: BuildS3PayloadArgs): S3CompressionJobCreation => {
111	    const {bucket, regionCode, s3Paths, scanner, values} = args;
112	    const payload: S3CompressionJobCreation = {
113	        bucket: bucket,
114	        inputType: CompressionJobInputType.S3,
115	        regionCode: regionCode,
116	        scanner: scanner,
117	    };
118	
119	    if (0 < s3Paths.length) {
120	        applyS3Paths(payload, s3Paths);
121	    }
122	    if (scanner) {
123	        if ("number" === typeof values.scanningIntervalSec) {
124	            payload.scanningIntervalSec = values.scanningIntervalSec;
125	        }
126	        if ("number" === typeof values.bufferFlushThresholdBytes) {
127	            payload.bufferFlushThresholdBytes = values.bufferFlushThresholdBytes;
128	        }
129	        if ("number" === typeof values.bufferTimeoutSec) {
130	            payload.bufferTimeoutSec = values.bufferTimeoutSec;
131	        }
132	        if ("number" === typeof values.bufferChannelCapacity) {
133	            payload.bufferChannelCapacity = values.bufferChannelCapacity;
134	        }
135	    }
136	    if (CLP_STORAGE_ENGINES.CLP_S === SETTINGS_STORAGE_ENGINE) {
137	        applyClpSFields(payload, values);
138	    }
139	
140	    return payload;
141	};
142	
143	type SubmitResult = {
144	    type: "compression";
145	    jobId: number;
146	} | {
147	    type: "scanner";
148	    jobIds: number[];
149	};
150	
151	/**
152	 * Formats the success message for a submit result.
153	 *
154	 * @param result
155	 * @return
156	 */
157	const getSuccessMessage = (result: SubmitResult): string => {
158	    if ("scanner" === result.type) {
159	        const ids = result.jobIds.join(", ");
160	        return 1 === result.jobIds.length ?
161	            `Scanner job created with ID: ${ids}` :
162	            `Scanner jobs created with IDs: ${ids}`;
163	    }
164	
165	    return `Compression job submitted with ID: ${result.jobId.toString()}`;
166	};
167	
168	/**
169	 * Filters S3 paths to valid non-empty strings.
170	 *
171	 * @param s3Paths
172	 * @return
173	 */
174	const filterValidS3Paths = (s3Paths?: string[]): string[] => {
175	    return s3Paths?.filter(
176	        (p): p is string => "string" === typeof p && 0 < p.trim().length,
177	    ) ?? [];
178	};
