27	/** Dashboard CRUD routes (Hono, chained for RPC type inference) */
28	export const dashboardRoutes = new Hono()
29	  .get("/", async (c): Promise<Response> => {
30	    const dashboards = await storage.list();
31	    return c.json(dashboards);
32	  })
33	  .post("/", tbValidator("json", CreateDashboardSchema as unknown as TSchema), async (c) => {
34	    const body = c.req.valid("json") as CreateDashboardRequest;
35	    const now = toMySQLDatetime();
36	    const dashboard: Dashboard = {
37	      id: nanoid(21),
38	      uid: body.uid ?? generateUid(),
39	      title: body.title,
40	      tags: body.tags ?? [],
41	      variables: body.variables ?? [],
42	      timeRange: body.timeRange ?? {from: "now-6h", to: "now"},
43	      panels: body.panels ?? [],
44	      version: 1,
45	      updatedAt: now,
46	      createdAt: now,
47	    };
48	    if (body.description !== undefined) {
49	      dashboard.description = body.description;
50	    }
51	    if (body.refreshInterval !== undefined) {
52	      dashboard.refreshInterval = body.refreshInterval;
53	    }
54	    await storage.create(dashboard);
55	    return c.json(dashboard, 201);
56	  })
57	  .get("/:uid", async (c) => {
58	    const {uid} = c.req.param();
59	    const dashboard = await storage.get(uid);
60	    if (!dashboard) {
61	      return c.json({error: "Dashboard not found"}, 404);
62	    }
63	    return c.json(dashboard);
64	  })
65	  .put("/:uid", tbValidator("json", UpdateDashboardSchema as unknown as TSchema), async (c) => {
66	    const {uid} = c.req.param();
67	    const existing = await storage.get(uid);
68	    if (!existing) {
69	      return c.json({error: "Dashboard not found"}, 404);
70	    }
71	    const body = c.req.valid("json") as UpdateDashboardRequest;
72	
73	    // Optimistic concurrency check
74	    if (body.version !== existing.version) {
75	      return c.json({error: "Version conflict", currentVersion: existing.version}, 409);
76	    }
77	
78	    const updated: Dashboard = {
79	      ...existing,
80	      title: body.title ?? existing.title,
81	      tags: body.tags ?? existing.tags,
82	      variables: body.variables ?? existing.variables,
83	      timeRange: body.timeRange ?? existing.timeRange,
84	      panels: body.panels ?? existing.panels,
85	      version: existing.version + 1,
86	      updatedAt: toMySQLDatetime(),
87	    };
88	    if (body.description !== undefined) {
89	      updated.description = body.description;
90	    }
91	    if (body.refreshInterval !== undefined) {
92	      updated.refreshInterval = body.refreshInterval;
