2	import type {DataFrame, DataField} from "../types.js";
3	import type {QueryResult, CLPQuery} from "../types.js";
4	import {QUERY_TIMEOUTS} from "../types.js";
5	
6	/** CLP-S search result document from MongoDB */
7	interface ClpSearchDocument {
8	  _id: unknown;
9	  message: string;
10	  timestamp: number;
11	  // CLP-S specific
12	  orig_file_path?: string;
13	  archive_id?: string;
14	  log_event_ix?: number;
15	  dataset?: string;
16	  // CLP specific
17	  orig_file_id?: string;
18	}
19	
20	/** Aggregation/timeline result document from MongoDB */
21	interface ClpAggregationDocument {
22	  _id: unknown;
23	  timestamp: number;
24	  count: number;
25	}
26	
27	/**
28	 * Converts CLP/CLP-S search result documents to a DataFrame.
29	 *
30	 * @param docs
31	 * @param refId
32	 * @param queryEngine
33	 * @param maxResults
34	 */
35	export function clpDocumentsToDataFrame(
36	  docs: ClpSearchDocument[],
37	  refId: string,
38	  queryEngine: CLP_QUERY_ENGINES,
39	  maxResults: number = 1000,
40	): DataFrame {
41	  if (0 === docs.length) {
42	    return {name: refId, fields: [], length: 0};
43	  }
44	
45	  const truncated = docs.length > maxResults;
46	  const displayDocs = truncated ?
47	    docs.slice(0, maxResults) :
48	    docs;
49	
50	  const fields: DataField[] = [
51	    {
52	      name: "timestamp",
53	      type: "time",
54	      values: displayDocs.map((d) => d.timestamp),
55	      config: {displayName: "Time"},
56	    },
57	    {
58	      name: "message",
59	      type: "string",
60	      values: displayDocs.map((d) => d.message),
61	      config: {displayName: "Message"},
62	    },
63	  ];
64	
65	  if ("clp-s" === queryEngine) {
66	    fields.push(
67	      {
68	        name: "dataset",
69	        type: "string",
70	        values: displayDocs.map((d) => d.dataset ?? ""),
71	        config: {displayName: "Dataset"},
72	      },
73	      {
74	        name: "archive_id",
75	        type: "string",
76	        values: displayDocs.map((d) => d.archive_id ?? ""),
77	        config: {displayName: "Archive ID"},
78	      },
79	    );
80	  } else {
81	    fields.push(
82	      {
83	        name: "orig_file_path",
84	        type: "string",
85	        values: displayDocs.map((d) => d.orig_file_path ?? ""),
86	        config: {displayName: "File"},
87	      },
88	    );
89	  }
90	
91	  return {
92	    name: refId,
93	    fields,
94	    length: displayDocs.length,
95	    ...(truncated ? {rowsTruncated: true} : {}),
96	  };
97	}
98	
99	/**
100	 * Converts aggregation/timeline result documents to a DataFrame.
101	 *
102	 * @param docs
103	 * @param refId
104	 */
105	export function clpAggregationToDataFrame(
106	  docs: ClpAggregationDocument[],
107	  refId: string,
108	): DataFrame {
109	  if (0 === docs.length) {
110	    return {name: refId, fields: [], length: 0};
111	  }
112	
113	  return {
114	    name: refId,
115	    fields: [
116	      {name: "timestamp", type: "time", values: docs.map((d) => d.timestamp)},
117	      {name: "count", type: "number", values: docs.map((d) => d.count)},
118	    ],
119	    length: docs.length,
120	  };
121	}
