123	/** CLP query datasource implementation */
124	export async function executeCLPQuery(
125	  query: CLPQuery,
126	  timeRange: {from: number; to: number},
127	  baseUrl: string = "http://localhost:3000",
128	): Promise<QueryResult> {
129	  const controller = new AbortController();
130	  const timeout = setTimeout(() => controller.abort(), QUERY_TIMEOUTS.CLP_QUERY_TIMEOUT_MS);
131	
132	  try {
133	    const response = await fetch(`${baseUrl}/api/datasource/clp/query`, {
134	      method: "POST",
135	      headers: {"Content-Type": "application/json"},
136	      body: JSON.stringify({
137	        requestId: `clp-${Date.now()}`,
138	        queries: [query],
139	        range: timeRange,
140	      }),
141	      signal: controller.signal,
142	    });
143	
144	    if (!response.ok) {
145	      return {data: [], error: `CLP query failed: ${response.status}`};
146	    }
147	
148	    const result = await response.json();
149	    return {data: result.data ?? []};
150	  } catch (error) {
151	    if (error instanceof DOMException && error.name === "AbortError") {
152	      return {data: [], error: "CLP query timed out"};
153	    }
154	    return {data: [], error: error instanceof Error ? error.message : "Unknown error"};
155	  } finally {
156	    clearTimeout(timeout);
157	  }
158	}
